import { CSSResult, html } from 'lit';
import { ifDefined } from 'lit/directives/if-defined.js';
import { XItem } from '../../internal/types.js';
import { util } from '../../internal/utils.js';
import { XButton, XUIElement } from '../../flame.js';
import styles from './toolbar.style.js';
import { classMap } from 'lit/directives/class-map.js';

export default class XToolBar extends XUIElement {
  static styles: CSSResult = styles;
  static defaultOptions = { park: 'left', showLabel: true, direction: 'row' };

  public addItem(args: XItem) {
    if (Array.isArray(this.data)) {
      this.setData([...this.data, args]);
    } else {
      this.setData([args]);
    }
  }

  public setItems(items: Array<XItem>) {
    this.setData(items);
  }

  private handleSlotClick(e: Event) {
    this.cleanAllSelected();
    (e.target as XButton).selected = true;
  }

  private handleMouseClick(item: XItem) {
    this.cleanAllSelected();
    for (let el of this.shadowRoot?.querySelectorAll('x-button') || []) {
      if (item.name === (el as XButton).name) {
        (el as XButton).selected = true;
      } else {
        (el as XButton).selected = false;
      }
    }
  }

  private cleanAllSelected() {
    for (let el of this.querySelectorAll('x-button')) {
      (el as XButton).selected = false;
    }
    for (let el of this.shadowRoot?.querySelectorAll('x-button') || []) {
      (el as XButton).selected = false;
    }
  }

  willUpdate(): void {
    super.willUpdate();
    util.setPosition(this as HTMLElement, this.options.park);
  }

  render() {
    return html`<div class="${classMap({ 'x-root': true, row: this.options.direction == 'row', column: this.options.direction == 'column' })}">
      <slot @click=${this.handleSlotClick}></slot>
      ${(util.isUndefined(this.data) ? [] : (this.data as Array<XItem>)).map(
        (item) => html`<x-button
          key=${ifDefined(item.key)}
          name=${item.name}
          x-options="border:'none'"
          title=${ifDefined(item.display)}
          style="${ifDefined(util.isBlank(item.style) ? this.options.style : item.style)}"
          onclick=${ifDefined(item.onClick)}
          @click=${() => this.handleMouseClick(item)}
        >
          <img src="${ifDefined(item.icon)}" />
          ${this.options.showLabel && !util.isBlank(item.display) ? html`<div slot="subfix" style="font-size:10px;">${item.display}</div>` : ''}
        </x-button>`,
      )}
    </div>`;
  }
}
