import { CSSResult, html, PropertyValues } from 'lit';
import { state } from 'lit/decorators.js';
import { XItem } from '../../internal/types.js';
import XUIElement from '../../internal/abstract.js';
import styles from './button-menu.style.js';

/**
 * 带下拉菜单的操作按钮组件。
 *
 * 提供「按钮 → 点击 → 展开 x-menu 下拉菜单 → 选择菜单项 → 自动关闭」的交互流程。
 * 适用于工具栏中的操作入口，如「新建」「导入」「更多操作」等需要二级选择的场景。
 *
 * ## 核心交互
 *
 * ```
 * 点击按钮         → _toggleMenu → _open = true  → 菜单展开，注册 document click 监听
 * 点击菜单项       → _closeMenu  → _open = false → 菜单关闭，注销 document click 监听
 * 点击组件外部     → _handleDocumentClick → composedPath 不含 this → _open = false
 * 再次点击按钮     → _toggleMenu → _open = false → 菜单关闭
 * ```
 *
 * ## 菜单数据来源
 *
 * 支持两种数据来源，优先级为「外部 setItems 覆盖 URL 加载」：
 * 1. **外部设置**：调用 {@link setItems} 传入 XItem 数组
 * 2. **URL 加载**：配置 `x-options="url:'/api/menu'"` 首次展开时懒加载 JSON
 *
 * ## 层叠上下文说明
 *
 * 下拉菜单使用 `position: absolute + z-index: 1000`，仅在其宿主容器（通常是 x-toolbar）
 * 的层叠上下文内竞争。因此要求宿主容器设置足够高的 z-index，确保不被 EasyUI 弹出层
 *（tooltip z-index: 9900000）等外部元素遮盖。
 *
 * ## 使用示例
 *
 * ```html
 * <!-- 静态菜单项 -->
 * <x-button-menu id="fileMenu">
 *   <span>文件</span>
 * </x-button-menu>
 * <script>
 *   document.getElementById('fileMenu').setItems([
 *     { name: 'new',    display: '新建',  icon: 'plus' },
 *     { name: 'open',   display: '打开',  icon: 'folder' },
 *     { name: 'save',   display: '保存',  icon: 'disk'  },
 *   ]);
 * </script>
 *
 * <!-- URL 懒加载菜单 -->
 * <x-button-menu x-options="url:'/api/actions',maxWidth:250">
 *   <span>操作</span>
 * </x-button-menu>
 * ```
 */
export default class XButtonMenu extends XUIElement {
  static styles: CSSResult = styles;

  /**
   * 组件默认配置。
   *
   * | 键        | 类型     | 默认值     | 说明                                 |
   * |-----------|----------|------------|--------------------------------------|
   * | `border`  | string   | `'fillet'` | 按钮边框样式，`false` / `'none'` 无边框 |
   * | `maxWidth`| number   | `200`      | 下拉菜单最大宽度（px）                 |
   * | `url`     | string   | `''`       | 菜单数据 JSON 接口地址，空则不加载     |
   * | `params`  | object   | `{}`       | URL 请求的查询参数                     |
   * | `parked`  | string   | `'right'`  | 子菜单展开方向，`'left'` / `'right'`   |
   */
  static defaultOptions = { border: 'fillet', maxWidth: 200, url: '', params: {}, parked: 'right' };

  /**
   * 菜单展开 / 收起状态。
   *
   * 使用 Lit `@state()` 装饰器标记为响应式属性：
   * - 值变更时自动触发组件重渲染
   * - `willUpdate` 中检测该属性的变更来注册 / 注销全局 document click 监听
   *
   * 仅通过 {@link _toggleMenu}、{@link _closeMenu}、{@link _handleDocumentClick}
   * 三个路径修改，确保状态转换集中可控。
   */
  @state() private _open = false;

  /**
   * 是否已从配置的 `url` 加载过菜单数据。
   *
   * 用于避免重复请求：当 `options.url` 不为空且菜单首次展开时触发懒加载，
   * 加载成功后置为 `true`，后续展开不再请求。
   * 调用 {@link setItems} 不会影响此标志（外部设置与 URL 加载是两条独立路径）。
   */
  private _menuLoaded = false;

  /**
   * 菜单项缓存数组。
   *
   * ## 双路径同步机制
   *
   * 存在两种时序：
   * 1. **组件已渲染**：`setItems()` → 缓存到 `_items` → 立即通过 `_menu.setItems()` 同步到 shadow DOM
   * 2. **组件未渲染**：`setItems()` → 仅缓存到 `_items` → 等待 `updated()` 回调中 catch-up 同步
   *
   * 这样无论外部在组件生命周期的哪个阶段调用 `setItems()`，菜单项都能正确送达 x-menu 子组件。
   */
  private _items: XItem[] = [];

  /**
   * shadowRoot 中 `<x-menu>` 子组件的懒引用。
   *
   * 每次访问时执行 `this.shadowRoot?.querySelector('x-menu')`：
   * - 组件未渲染时返回 `undefined`，调用方通过 `?.` 安全跳过
   * - 不存在缓存过期问题，因为 x-menu 是静态子组件不会动态替换
   *
   * 封装为 getter 而非在 `connectedCallback` 中缓存引用的原因是：
   * Lit 可能在运行时重新创建 shadow DOM（如 hot reload），缓存引用会指向已销毁的节点。
   */
  private get _menu() {
    return this.shadowRoot?.querySelector('x-menu') as any;
  }

  /* ------------------------------------------------------------------ */
  /*  Public API                                                         */
  /* ------------------------------------------------------------------ */

  /**
   * 设置下拉菜单的菜单项列表。
   *
   * 若 shadow DOM 中的 `<x-menu>` 已渲染，则立即同步数据；
   * 否则仅缓存到 `_items`，等待 {@link updated} 中 catch-up 同步。
   *
   * @param items - XItem 数组，每项支持以下字段：
   *   | 字段       | 类型                  | 说明                                        |
   *   |------------|-----------------------|---------------------------------------------|
   *   | `name`     | `string`              | 唯一标识，用于事件回调中识别被点击的项        |
   *   | `display`  | `string`              | 菜单项显示文本                               |
   *   | `icon`     | `string` _(可选)_     | 菜单项图标（fa class 或图片 URL）             |
   *   | `url`      | `string` _(可选)_     | 点击后打开的 URL                              |
   *   | `onClick`  | `string` _(可选)_     | 点击时执行的 JS 脚本（eval 方式）             |
   *   | `close`    | `boolean`_(可选)_    | 点击后是否关闭菜单，默认 `true`               |
   *   | `leaf`     | `boolean`_(可选)_    | 是否为叶子节点，`false` 表示有子菜单，默认 `true` |
   *   | `children` | `XItem[]`_(可选)_    | 子菜单项列表                                 |
   *
   * @example
   * ```js
   * buttonMenu.setItems([
   *   { name: 'new',  display: '新建', icon: 'plus' },
   *   { name: 'open', display: '打开', icon: 'folder', leaf: false, children: [
   *     { name: 'openRecent', display: '最近打开' },
   *     { name: 'openFrom',   display: '从...打开' },
   *   ]},
   * ]);
   * ```
   */
  public setItems(items: XItem[]) {
    this._items = items;
    this._menu?.setItems(items);
  }

  /**
   * 从后端 URL 加载 JSON 格式的菜单数据。
   *
   * 委托给内部 `<x-menu>` 组件的 {@link XMenu.loadMenuFromUrl} 方法处理 HTTP 请求和 JSON 解析。
   * 通常不需要外部调用 —— 若配置了 `options.url`，首次点击按钮时会自动触发懒加载。
   *
   * @param url    - 菜单数据接口地址，返回 JSON 格式 `XItem[]`
   * @param params - 查询参数键值对，拼接到 URL 的 query string
   *
   * @example
   * ```js
   * // 手动触发加载
   * buttonMenu.loadFromUrl('/api/dynamicMenu', { context: 'toolbar' });
   * ```
   */
  public loadFromUrl(url: string, params?: Record<string, string>) {
    this._menu?.loadMenuFromUrl(url, params);
  }

  /* ------------------------------------------------------------------ */
  /*  Event handlers                                                     */
  /* ------------------------------------------------------------------ */

  /**
   * 全局 document click 监听器。
   *
   * 注册时机：菜单展开时（`_open` 从 `false` → `true`），见 {@link willUpdate}
   * 注销时机：菜单关闭时（`_open` 从 `true` → `false`）或组件从 DOM 移除时
   *
   * ## 为什么使用 `composedPath()` 而非 `target`
   *
   * ```
   * document
   *   └─ <body>
   *       └─ <x-button-menu>              ← this
   *           └─ #shadow-root
   *               └─ <div class="x-menu-drop">
   *                   └─ <x-menu>
   *                       └─ #shadow-root
   *                           └─ <x-cell>  ← 点击目标
   * ```
   *
   * 点击 `<x-cell>` 时 `e.target` 是 `<x-cell>`（在 x-menu 的 shadow DOM 内），
   * 而非 `<x-button-menu>`。仅靠 `target` 无法判断点击是否发生在组件内部。
   * `composedPath()` 返回事件穿透 shadow DOM 边界后的完整路径数组，
   * 必定包含 `<x-button-menu>`（即 `this`），因此可以正确判断。
   *
   * @param e - 全局捕获的 click 事件
   */
  private _handleDocumentClick = (e: MouseEvent) => {
    if (!e.composedPath().includes(this)) {
      this._open = false;
    }
  };

  /**
   * 按钮点击处理器：切换下拉菜单的展开 / 收起状态。
   *
   * ## 行为细节
   *
   * 1. **阻止冒泡**：`e.stopPropagation()` 防止点击按钮的事件冒泡到 document，
   *    避免被 `_handleDocumentClick` 误捕获（虽然 composedPath 包含 this 不会关闭，
   *    但阻止冒泡可以减少不必要的全局监听器执行）
   *
   * 2. **懒加载**：若配置了 `options.url` 且尚未加载（`_menuLoaded === false`），
   *    在菜单首次展开前从 URL 拉取菜单数据
   *
   * 3. **切换状态**：`_open = !_open`，Lit 自动调度重渲染
   *
   * @param e - 按钮的 click 事件
   */
  private _toggleMenu = (e: MouseEvent) => {
    e.stopPropagation();

    if (!this._open && !this._menuLoaded && this.options.url) {
      this._menu?.loadMenuFromUrl(this.options.url, this.options.params);
      this._menuLoaded = true;
    }

    this._open = !this._open;
  };

  /**
   * 菜单项点击处理器：关闭下拉菜单。
   *
   * 绑定在 `.x-menu-drop` 容器上，捕获所有从内部 `<x-menu>` 子组件冒泡上来的 click 事件。
   *
   * ## 事件冒泡路径
   *
   * ```
   * x-cell (click 发生)
   *   → x-menu shadow DOM 冒泡
   *   → x-menu 宿主元素（composed: true 穿透 shadow boundary）
   *   → <div class="x-menu-drop">  ← @click="${this._closeMenu}" 在此捕获
   *   → button-menu shadow DOM
   *   → document（_handleDocumentClick 中 composedPath 含 this，跳过关闭）
   * ```
   *
   * ## 为什么不需要区分菜单项类型
   *
   * 无论点击的是叶子项（执行操作）还是父项（展开子菜单），统一关闭菜单是符合用户预期的：
   * - 叶子项：执行 `onClick` 脚本 → 关闭菜单
   * - 父项：子菜单通过 hover 展开，click 触发父项自身操作 → 关闭菜单
   *
   * 嵌套子菜单中的项点击也会冒泡到达此处理函数，因此选中深层菜单项也能正确关闭整个菜单链。
   */
  private _closeMenu = () => {
    this._open = false;
  };

  /* ------------------------------------------------------------------ */
  /*  Lit lifecycle                                                      */
  /* ------------------------------------------------------------------ */

  /**
   * 组件每次更新前的生命周期回调。
   *
   * ## 核心职责：document click 监听的注册与注销
   *
   * 仅在 `_open` 属性发生变化时执行，避免其他属性变更引起不必要的 DOM 操作：
   *
   * | `_open` 变化      | 操作                                                         |
   * |--------------------|--------------------------------------------------------------|
   * | `false` → `true`   | `document.addEventListener('click', _handleDocumentClick)`   |
   * | `true` → `false`   | `document.removeEventListener('click', _handleDocumentClick)`|
   * | 未变化              | 跳过                                                        |
   *
   * ## 为什么使用全局 document 监听而非组件级事件代理
   *
   * 组件内部可以监听 click 事件（如 `_closeMenu`），但要检测「点击组件外部」无法仅靠内部事件。
   * 必须借助 document 级别的全局监听。为最小化性能影响，仅在菜单展开期间注册，
   * 关闭后立即注销 —— 大部分时间组件处于关闭状态，零开销。
   *
   * @param _changedProperties - Lit 提供的变更属性映射，key 为属性名，value 为旧值
   */
  willUpdate(_changedProperties: PropertyValues): void {
    super.willUpdate(_changedProperties);
    if (_changedProperties.has('_open')) {
      if (this._open) {
        document.addEventListener('click', this._handleDocumentClick);
      } else {
        document.removeEventListener('click', this._handleDocumentClick);
      }
    }
  }

  /**
   * 组件从 DOM 中移除时的清理回调。
   *
   * 确保即使组件在菜单展开状态下被移除（如通过父组件条件渲染），
   * 全局 document click 监听器也能被正确清理，防止：
   * 1. **内存泄漏**：监听器持有 `this`（组件实例）引用，阻止 GC
   * 2. **僵尸回调**：组件已销毁但监听器仍触发，访问已销毁的 shadow DOM 导致运行时错误
   */
  disconnectedCallback(): void {
    super.disconnectedCallback();
    document.removeEventListener('click', this._handleDocumentClick);
  }

  /**
   * 组件每次更新完成后的生命周期回调。
   *
   * ## 核心职责：catch-up 同步缓存的菜单项
   *
   * 当外部在组件首次渲染前调用 `setItems()` 时，shadow DOM 尚未创建，
   * `_menu` 为 `undefined`，数据仅缓存到 `_items`。
   * 组件渲染完成后，`updated()` 将缓存的菜单项同步到 shadow DOM 中的 `<x-menu>` 子组件。
   *
   * ## 为什么每次更新都执行
   *
   * 不使用 `_changedProperties` 精确判断 `_items` 是否变化的原因是：
   * `_items` 是普通私有字段而非 `@state()` 属性，不会出现在 `_changedProperties` 中。
   * 但由于 `setItems()` 在菜单已渲染时会直接同步（不走 `updated`），因此 `updated`
   * 中的同步仅在第一帧或极少数 catch-up 场景触发，开销可以忽略。
   *
   * @param _changedProperties - Lit 提供的变更属性映射
   */
  protected updated(_changedProperties: Map<string, any>): void {
    super.updated(_changedProperties);
    if (this._items.length) {
      this._menu?.setItems(this._items);
    }
  }

  /* ------------------------------------------------------------------ */
  /*  Render                                                             */
  /* ------------------------------------------------------------------ */

  /**
   * 渲染组件的 Shadow DOM 内容。
   *
   * ## 模板结构
   *
   * ```
   * <x-button-menu>
   *   #shadow-root
   *   ├─ <button class="x-btn fillet">
   *   │    <slot></slot>           ← 按钮文本 / 图标（light DOM 投射）
   *   │    <i class="fa caret-down"></i>  ← 下拉箭头
   *   │  </button>
   *   └─ <div class="x-menu-drop">  ← 下拉菜单容器，绝对定位在按钮下方
   *        <x-menu mode="list">     ← 菜单项列表子组件
   *        </x-menu>
   *      </div>
   * ```
   *
   * ## 样式类名计算
   *
   * - `x-menu-drop` 始终渲染，通过附加 `open` class 控制可见性（CSS `display: none/block`），
   *   而非条件渲染整个元素。这样避免了菜单 DOM 的反复创建 / 销毁，菜单项状态得以保留。
   * - `borderClass` 支持三种值：`'fillet'`（圆角）、`'none'`（无边框）、自定义 border 样式名
   */
  render() {
    const b = this.options.border;
    const borderClass = (b === false || b === 'none') ? 'none' : (b || 'fillet');
    const maxWidth = this.options.maxWidth ? `max-width:${this.options.maxWidth}px` : '';

    return html`
      <button class="x-btn ${borderClass}" @click="${this._toggleMenu}">
        <slot></slot>
        <i class="fa caret-down"></i>
      </button>
      <div class="x-menu-drop ${this._open ? 'open' : ''}" style="${maxWidth}" @click="${this._closeMenu}">
        <x-menu x-options="mode:'list',parked:'${this.options.parked || 'right'}'"></x-menu>
      </div>
    `;
  }
}
