import { css } from 'lit';
import componentStyles from '../../styles/component.styles';

export default css`
  ${componentStyles}
  :host {
    display: block;
    cursor: pointer;
  }
  .x-root {
    display: inline-flex;
    height: 100%;
  }
  .x-left {
    flex: 1;
    align-items: center;
    justify-content: flex-start;
    display: inline-flex;
  }
  .x-left > i {
    margin: auto 0;
    font-size: 12px;
    white-space: nowrap;
  }
  .x-right {
    align-items: center;
    justify-content: flex-end;
    display: inline-flex;
  }
  .x-row {
    flex-direction: row;
  }
  .x-column {
    flex-direction: column;
  }
  i {
    font-style: normal;
  }
`;
