import { CSSResult, html } from 'lit';
import { ifDefined } from 'lit/directives/if-defined.js';
import { classMap } from 'lit/directives/class-map.js';
import { state } from 'lit/decorators.js';
import { Parked, XItem } from '../../internal/types.js';
import { util } from '../../internal/utils.js';
import XUIElement from '../../internal/abstract.js';
import styles from './menu.style.js';

export default class XMenu extends XUIElement {
  static styles: CSSResult = styles;
  static defaultOptions = {
    park: 'auto',
    mode: 'list',
    parked: 'auto',
    url: '',
    params: {},
    header: { height: 10 },
    footer: { height: 10 },
    spLine: true,
  };

  private _lastUrl: string = '';

  /** Key of the item whose sub-menu popup is currently open. null means no open sub-menu. */
  @state() private _openSubMenuKey: string | null = null;

  /** Actual computed placement after viewport boundary check. */
  @state() private _resolvedPlacement: Parked = 'right';

  /** Timer handle for delayed close (prevents flicker on hover out). */
  private _subMenuCloseTimer: ReturnType<typeof setTimeout> | null = null;

  /** Timer handle for delayed open (prevents flicker when sliding past items). */
  private _subMenuOpenTimer: ReturnType<typeof setTimeout> | null = null;

  constructor() {
    super();
    this._lastUrl = '';
  }

  private get _items(): Array<XItem> {
    return (this.data as Array<XItem>) || [];
  }

  public setItems(items: Array<XItem>, script?: string) {
    this.data = items;
    if (script && !util.isBlank(script)) {
      this._applyOnClick(items, script);
    }
  }

  /**
   * 从后端 URL 加载 JSON 格式的菜单数据并填充菜单项。
   * JSON 格式与 XUIAction 的字段定义保持一致。
   * 响应结构: { status, message, data: XItem[] } 或直接是 XItem[]
   */
  public loadMenuFromUrl(url: string, params?: Record<string, string>) {
    if (util.isBlank(url)) return;

    let reqUrl = url;
    const reqParams = params || this.options.params || {};
    const qs = new URLSearchParams(reqParams).toString();
    if (qs) {
      reqUrl += (url.indexOf('?') >= 0 ? '&' : '?') + qs;
    }
    fetch(reqUrl)
      .then((response) => response.json())
      .then((json) => {
        const list = Array.isArray(json) ? json : json.data || json;
        if (Array.isArray(list)) {
          const items = list.map((item) => this._mapMenuItem(item));
          this.setItems(items);
        }
      })
      .catch((err) => {
        console.error('x-menu load failed:', err);
      });
  }

  /** 将服务端 JSON 对象映射为 XItem 格式，处理字段名差异（如 onclick → onClick） */
  private _mapMenuItem(raw: any): XItem {
    const item: XItem = {
      key: raw.key || raw.id,
      name: raw.name || raw.id,
      display: raw.display,
      icon: raw.icon,
      style: raw.style,
      url: raw.url,
      close: raw.close === true,
      leaf: raw.leaf !== false,
      onClick: raw.onclick || raw.onClick,
      beforeJS: raw.beforeJS || raw.beforejs,
      afterJS: raw.afterJS || raw.afterjs,
      processor: raw.processor,
      winType: raw.winType,
    };
    if (raw.children && raw.children.length) {
      item.children = raw.children.map((child: any) => this._mapMenuItem(child));
    }
    return item;
  }

  private _applyOnClick(items: Array<XItem>, script: string) {
    for (const item of items) {
      if (item.children?.length) {
        this._applyOnClick(item.children, script);
      } else {
        item.onClick = util.isBlank(item.onClick) ? script : item.onClick + ';' + script;
      }
    }
  }

  private _toggleCollapse(item: XItem) {
    item.collapse = !item.collapse;
    this.requestUpdate();
  }

  willUpdate(): void {
    super.willUpdate();
    util.setPosition(this as HTMLElement, this.options.park);

    const url = this.options.url;
    if (url && url !== this._lastUrl) {
      this._lastUrl = url;
      this.loadMenuFromUrl(url, this.options.params);
    }
  }

  disconnectedCallback(): void {
    super.disconnectedCallback();
    if (this._subMenuCloseTimer) { clearTimeout(this._subMenuCloseTimer); this._subMenuCloseTimer = null; }
    if (this._subMenuOpenTimer) { clearTimeout(this._subMenuOpenTimer); this._subMenuOpenTimer = null; }
  }

  /**
   * Resolve the actual sub-menu placement by checking viewport boundaries.
   * When parked is 'auto', measure parent item position and flip
   * to 'left' if expanding right would overflow the viewport.
   */
  private _resolvePlacement(itemKey: string): Parked {
    const placement = (this.options.parked as Parked) || 'auto';
    if (placement !== 'auto') return placement;

    const parentCell = this.shadowRoot?.querySelector(`[data-x-menu-item="${itemKey}"]`) as HTMLElement;
    if (!parentCell) return 'right';

    const parentRect = parentCell.getBoundingClientRect();
    const viewportWidth = window.innerWidth;
    const estimatedWidth = this.options.maxWidth ? Number(this.options.maxWidth) : 200;

    const rightOverflow = parentRect.right + estimatedWidth > viewportWidth - 4;
    if (rightOverflow) {
      const leftOverflow = parentRect.left - estimatedWidth < 4;
      if (leftOverflow) {
        const spaceRight = viewportWidth - parentRect.right;
        const spaceLeft = parentRect.left;
        return spaceRight >= spaceLeft ? 'right' : 'left';
      }
      return 'left';
    }
    return 'right';
  }

  private _onItemMouseEnter(item: XItem) {
    if (this._subMenuCloseTimer) { clearTimeout(this._subMenuCloseTimer); this._subMenuCloseTimer = null; }
    if (this._subMenuOpenTimer) { clearTimeout(this._subMenuOpenTimer); this._subMenuOpenTimer = null; }

    const key = item.key || item.name;
    if (this._openSubMenuKey === key) return;

    this._subMenuOpenTimer = setTimeout(() => {
      this._openSubMenuKey = key;
      this._resolvedPlacement = this._resolvePlacement(key);
      this.requestUpdate();
    }, 100);
  }

  private _onItemMouseLeave(item: XItem) {
    if (this._subMenuOpenTimer) { clearTimeout(this._subMenuOpenTimer); this._subMenuOpenTimer = null; }

    this._subMenuCloseTimer = setTimeout(() => {
      if (this._openSubMenuKey === (item.key || item.name)) {
        this._openSubMenuKey = null;
        this.requestUpdate();
      }
    }, 150);
  }

  private _onSubMenuMouseEnter() {
    if (this._subMenuCloseTimer) { clearTimeout(this._subMenuCloseTimer); this._subMenuCloseTimer = null; }
  }

  private _onSubMenuMouseLeave(item: XItem) {
    this._subMenuCloseTimer = setTimeout(() => {
      if (this._openSubMenuKey === (item.key || item.name)) {
        this._openSubMenuKey = null;
        this.requestUpdate();
      }
    }, 150);
  }

  protected render() {
    if (this.options.mode === 'tree') {
      return html`<ul class="x-root">${this._items.map((item) => this._renderNode(item))}</ul>`;
    }

    return html`<div class="x-root x-list ${this._openSubMenuKey ? 'x-list-popup-active' : ''}">
      <slot name="header"></slot>
      <slot></slot>
      ${this._items.map((item) => this._renderListItem(item))}
      <slot name="footer"></slot>
      <span class="sp-line"></span>
    </div>`;
  }

  protected _renderNode(item: XItem): any {
    const isFolder = !item.leaf && item.children?.length;
    return html`<li>
      ${isFolder
        ? html`${this._renderFolder(item)}<ul>${item.children!.map((child) => this._renderNode(child))}</ul>`
        : this._renderLeaf(item)}
    </li>`;
  }

  private _renderFolder(item: XItem) {
    return html`<x-cell
      part="cell"
      id="${ifDefined(item.key)}"
      name="${item.name}"
      icon="${ifDefined(item.icon)}"
      @click="${() => this._toggleCollapse(item)}"
      class="${classMap({ expend: item.collapse !== true, collapse: item.collapse === true })}"
    >
      <i title="${ifDefined(item.display)}"><b style="font-style:normal;">${item.display}</b></i>
    </x-cell>`;
  }

  private _renderLeaf(item: XItem) {
    return html`<x-cell
      part="cell"
      id="${ifDefined(item.key)}"
      name="${item.name}"
      icon="${ifDefined(item.icon)}"
      title="${ifDefined(item.display)}"
      ?close="${item.close === true}"
      onclick="${ifDefined(item.onClick)}"
      .data=${item}
    ></x-cell>`;
  }

  /**
   * Render a list-mode item, conditionally wrapping it for sub-menu support.
   * Items with non-leaf children get a wrapper that handles hover/click to
   * show a cascading popup sub-menu.
   */
  private _renderListItem(item: XItem) {
    const hasChildren = !item.leaf && item.children?.length;
    if (!hasChildren) {
      return this._renderLeaf(item);
    }

    const key = item.key || item.name;
    const isOpen = this._openSubMenuKey === key;
    const placement = isOpen ? this._resolvedPlacement : ((this.options.parked as Parked) || 'auto') === 'left' ? 'left' : 'right';

    return html`<div class="x-item-wrapper"
      data-x-menu-item="${key}"
      @mouseenter="${() => this._onItemMouseEnter(item)}"
      @mouseleave="${() => this._onItemMouseLeave(item)}">
      ${this._renderLeaf(item)}
      <i class="x-sub-arrow"></i>
      ${isOpen ? html`
        <div class="x-sub-menu-popup x-sub-menu-open x-sub-menu-${placement}"
          @mouseenter="${() => this._onSubMenuMouseEnter()}"
          @mouseleave="${() => this._onSubMenuMouseLeave(item)}">
          <x-menu .data="${item.children}"
            x-options="mode:'list',parked:'${this.options.parked || 'auto'}'">
          </x-menu>
        </div>
      ` : ''}
    </div>`;
  }
}
