/**
 * XUI 模块自动加载入口。
 *
 * 职责：
 * 1. 初始化 String 原型扩展（确保低版本浏览器兼容）。
 * 2. 将 flame / xui 命名空间挂载到 `window` 全局对象，
 *    使 HTML 内联脚本（如 popup.html 的 onclick）可直接引用。
 * 3. 调用 `flame.initMeshGird(jQuery)` 初始化 EasyUI 扩展。
 *
 * 此文件由 `src/flame.ts` 通过 `import './flame-autoloader.js'` 引入，
 * 在 UMD 模块加载时自动执行。
 */
import { flame, util, shell } from './flame.js';

// ── String 原型扩展（低版本浏览器兼容） ───────────────────────────────

/** 判断字符串是否以指定前缀开头，兼容不支持 `startsWith` 的环境。 */
(String.prototype as any).startWith = (String.prototype as any).startWith ||
  function (this: string, s: string): boolean {
    if (s == null || s == '' || this.length == 0 || s.length > this.length) return false;
    return this.substr(0, s.length) == s;
  };

/** 判断字符串是否以指定后缀结尾，兼容不支持 `endsWith` 的环境。 */
(String.prototype as any).endWith = (String.prototype as any).endWith ||
  function (this: string, s: string): boolean {
    if (s == null || s == '' || this.length == 0 || s.length > this.length) return false;
    return this.substring(this.length - s.length) == s;
  };

/** 去除字符串首尾空白，兼容不支持 `trim` 的环境。 */
(String.prototype as any).trim = (String.prototype as any).trim ||
  function (this: string): string {
    return this.replace(/^\s\s*/, '').replace(/\s\s*$/, '');
  };

/**
 * 字符串格式化 `"Hello {0}, you have {1} messages".format("Tom", 5)`。
 * 兼容不支持此方法的低版本浏览器。
 */
(String as any).format = (String as any).format || function (): string {
  let s = arguments[0];
  for (let i = 0; i < arguments.length - 1; i++) {
    s = s.replace(new RegExp('\\{' + i + '\\}', 'gm'), arguments[i + 1]);
  }
  return s;
};

// ── 全局挂载 ──────────────────────────────────────────────────────────
/**
 * 将 TypeScript namespace 编译产物合并到 `window` 全局对象。
 * 使用 `Object.assign(window.xxx || {}, ...)` 确保不覆盖已存在的属性
 * （例如 `flame.xui.js` 可能先于 `xui.lit.js` 加载并初始化了 flame.xui.Cache）。
 */

// window.flame — popup.html 的 `flame.submitForm(...)` 等全局调用入口
Object.assign(window as any, { flame: Object.assign((window as any).flame || {}, flame) });

// window.xui  — Lit Web Component 侧的工具命名空间
Object.assign(window as any, { xui: Object.assign((window as any).xui || {}, { util, shell }) });

// 常用工具函数单独挂载到 window，便于 HTML onclick 中直接使用短名调用
Object.assign(window as any, {
  isBlank: util.isBlank,
  isOid: util.isOid,
  getFunction: util.getFunction,
  getPosition: util.getPosition,
  removeElement: util.removeElement,
  datebox$local: util.datebox$local,
  datebox$en_US: util.datebox$en_US,
  datebox$zh_CN: util.datebox$zh_CN,
});

// ── 插件初始化 ────────────────────────────────────────────────────────
/**
 * 初始化 EasyUI 扩展：
 * - datagrid 编辑器（addEditor / removeEditor）
 * - combobox 默认配置（只读 / 自动高度）
 * - datebox 日期解析器
 * - meshgrid 自定义组件注册
 */
flame.initMeshGird(jQuery);
