import { CSSResult, html } from 'lit';
import { classMap } from 'lit/directives/class-map.js';
import { util } from '../../internal/utils.js';
import XUIElement from '../../internal/abstract.js';
import styles from './cell.style.js';

export default class XCell extends XUIElement {
  static styles: CSSResult = styles;
  static defaultOptions = { icon: '', text: '', direction: 'row' };

  render() {
    return html`
      <div class="${classMap({ 'x-root': true, 'x-row': this.options.direction == 'row', 'x-column': this.options.direction == 'column' })}">
        <span class="x-left">
          ${util.isBlank(this.icon) ? html`<span part="icon" style="display:inline-block"></span>` : html`<img part="icon" src="${this.icon}" style="margin:auto 0" />`} ${util.isBlank(this.title) ? '' : html`<i part="title">${this.title}</i>`}
          <slot></slot>
        </span>
        <span class="x-right">
          <slot name="actions"></slot>
        </span>
      </div>
    `;
  }
}
