import { CSSResult, html } from 'lit';
import { property } from 'lit/decorators.js';
import { classMap } from 'lit/directives/class-map.js';
import { ifDefined } from 'lit/directives/if-defined.js';
import { OnCollapseEvent, OnExpandEvent, OnLockEvent } from '../../internal/events.js';
import styles from './composer.style.js';
import XPanel from '../panel/panel.component.js';

export default class XComposer extends XPanel {
  static styles: CSSResult = styles;
  static defaultOptions = { park: 'top', draggable: false, header: { height: 28 }, footer: { height: 20 }, closable: false, border: false };
  static customEvents = { 'o-lock': OnLockEvent, 'o-expand': OnExpandEvent, 'o-collapse': OnCollapseEvent };

  @property({ type: Boolean }) locked: boolean = false;

  public hideComposer() {
    /** 锁定状态不允许隐藏Composer */
    if (!this.isLocked()) {
      this.hide();
      this.emit('o-collapse');
    }
  }

  public showComposer(title?: string) {
    if (title) {
      this.title = title;
    }
    this.show();
    this.emit('o-expand');
  }

  public isVisible() {
    return this.style.visibility == 'visible';
  }

  public isLocked() {
    return this.locked;
  }

  public swapLockStatus() {
    this.locked = !this.locked;
    this.emit('o-lock');
  }

  initialize() {
    super.initialize();
    if (this.hasOption('locked')) {
      this.locked = this.getOption('locked');
    }
  }

  _uiHeader() {
    return html`<i style="padding-left:5px;font-weight:bold;font-style:normal;">${ifDefined(this.title)}</i><slot name="logo"></slot>`;
  }

  _uiMain() {
    return html`<section>
        <slot></slot>
      </section>
      <aside class="sidebar" style="font-size:14px;">
        <i class="fa chevron" @click="${this.hideComposer}"></i>
        <i class="${classMap({ fa: true, unlock: !this.locked, lock: this.locked })}" style="margin-top:5px;" @click="${this.swapLockStatus}"></i>
      </aside>`;
  }
}
