import { css } from 'lit';
import 'font-awesome/css/font-awesome.css';

export default css`
  :host {
    box-sizing: border-box;
    z-index: 1;
  }
  :host *,
  :host *::before,
  :host *::after {
    box-sizing: inherit;
  }
  [hidden] {
    display: none !important;
  }
  .fa {
    display: inline-block;
    font: normal normal normal 14px/1 FontAwesome;
    font-size: inherit;
    text-rendering: auto;
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
  }
  .x-close,
  .x-maximize,
  .x-minimize,
  .x-restore {
    width: 20px;
    height: 20px;
  }
  .x-close:before {
    content: url('data:image/svg+xml;charset=UTF-8,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" stroke="green" stroke-width="1"><path d="M 6 6 14 14"/><path d="M 6 14 14 6"/></svg>');
  }
  .x-maximize:before {
    content: url('data:image/svg+xml;charset=UTF-8,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" stroke="green" stroke-width="1"><path d="M 5 6 5 15"/><path d="M 5 15 15 15"/><path d="M 15 15 15 6"/><path d="M 15 6 5 6"/></svg>');
  }
  .x-minimize:before {
    content: url('data:image/svg+xml;charset=UTF-8,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" stroke="green" stroke-width="1"><path d="M 4 12 16 12"/></svg>');
  }
  .x-restore::before {
    content: url('data:image/svg+xml;charset=UTF-8,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" stroke="green" stroke-width="1"><path d="M 5 6 5 12"/><path d="M 5 12 12 12"/><path d="M 12 12 12 6"/><path d="M 12 6 5 6"/><path d="M 8 15 15 15"/><path d="M 15 15 15 8"/></svg>');
  }
`;
