import { css } from 'lit';
import panelStyles from '../panel/panel.style.js';

export default css`
  ${panelStyles}

  :host {
    min-width: 100px;
    min-height: 50px;
    border-radius: 5px;
    overflow: hidden;
    border: 1px solid #80cefc;
    box-shadow: 1px 1px 1px #f0f0f0;
    -moz-box-shadow: 1px 1px 1px #f0f0f0;
    -webkit-box-shadow: 1px 1px 1px #f0f0f0;
  }
  :host > main {
    flex: 1;
    overflow: auto;
    background-color: white;
  }
  .main-left {
    position: absolute;
    left: 0px;
    top: 0px;
    bottom: 0px;
    width: 2px;
    background-color: #80cefc;
  }
  .main-right {
    position: absolute;
    right: 0px;
    top: 0px;
    bottom: 0px;
    width: 2px;
    background-color: #80cefc;
  }
  .main-bottom {
    position: absolute;
    left: 0px;
    right: 0px;
    bottom: 0px;
    height: 2px;
    background-color: #80cefc;
  }
  .main-content {
    position: absolute;
    background-color: white;
    inset : 0px 2px 2px 2px;
    overflow: auto !important;
  }
  .ew-resize {
    cursor: ew-resize;
  }
  .ns-resize {
    cursor: ns-resize;
  }
  @keyframes expand {
    from {
      width: 0;
    }
    to {
      width: 200px; /* 设置div的最终宽度 */
    }
  }
`;
